// BusMap.jsx
import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import "./BusMap.css"; // Make sure the filename matches exactly

// Marker icons
const normalIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/190/190411.png",
  iconSize: [25, 25],
});

const ghostIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/565/565547.png",
  iconSize: [25, 25],
});

const anomalyIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/1828/1828665.png",
  iconSize: [25, 25],
});

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [alerts, setAlerts] = useState([]);

  // Fetch buses from backend
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        setBuses(data || []); // fallback to empty array
        detectAnomalies(data || []);
        setLoading(false);
      } catch (err) {
        console.error("Error fetching buses:", err);
        setBuses([]);
        setLoading(false);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // refresh every 2 min
    return () => clearInterval(interval);
  }, []);

  // Anomaly detection (example: mark ghost buses as anomalies)
  const detectAnomalies = (busData) => {
    const newAlerts = [];
    busData.forEach((bus) => {
      if (bus.isGhost) {
        newAlerts.push(`Ghost bus detected at ${bus.lat.toFixed(3)}, ${bus.lon.toFixed(3)}`);
      }
    });
    setAlerts(newAlerts);
  };

  return (
    <div className="bus-map-container">
      {alerts.length > 0 && (
        <div className="alert-box">
          {alerts.map((alert, index) => (
            <p key={index} className="alert-message">{alert}</p>
          ))}
        </div>
      )}

      {loading ? (
        <p>Loading buses...</p>
      ) : (
        <MapContainer
          center={[40.7128, -74.006]} // New York default center
          zoom={12}
          style={{ height: "600px", width: "100%" }}
        >
          <TileLayer
            url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
            attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
          />
          {buses.map((bus) => (
            <Marker
              key={bus.id}
              position={[bus.lat, bus.lon]}
              icon={bus.isGhost ? ghostIcon : normalIcon}
            >
              <Popup>
                <div>
                  <p><strong>Bus ID:</strong> {bus.id}</p>
                  <p><strong>Status:</strong> {bus.isGhost ? "Ghost" : "Normal"}</p>
                  {bus.isGhost && <p style={{ color: "red" }}>Anomaly detected!</p>}
                </div>
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      )}
    </div>
  );
}
